import os
import subprocess
from google.cloud import storage

def validate_conversion_options(options):
    allowed_options = {'resize', 'rotate', 'format'}
    return all(option in allowed_options for option in options.keys())

def image_conversion(event, context):
    bucket_name = event['bucket']
    file_name = event['name']
    metadata = event.get('metadata', {})
    
    conversion_options = metadata.get('conversion_options', {})
    if not validate_conversion_options(conversion_options):
        raise ValueError("Invalid conversion options provided.")
    
    storage_client = storage.Client()
    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(file_name)
    
    local_file_path = f"/tmp/{file_name}"
    blob.download_to_filename(local_file_path)
    
    output_file_name = f"converted-{file_name}"
    output_file_path = f"/tmp/{output_file_name}"
    
    command = ['convert', local_file_path]
    
    if 'resize' in conversion_options:
        command.extend(['-resize', conversion_options['resize']])
    if 'rotate' in conversion_options:
        command.extend(['-rotate', conversion_options['rotate']])
    if 'format' in conversion_options:
        output_file_path = f"/tmp/{os.path.splitext(output_file_name)[0]}.{conversion_options['format']}"
    
    command.append(output_file_path)
    
    try:
        subprocess.call(command)
    except Exception as e:
        raise RuntimeError(f"ImageMagick conversion failed: {e}")
    
    output_blob = bucket.blob(output_file_name)
    output_blob.upload_from_filename(output_file_path)
    
    os.remove(local_file_path)
    os.remove(output_file_path)